import android.util.Log
import timber.log.Timber

class LoggingTree : Timber.DebugTree() {

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        when (priority) {
            Log.VERBOSE -> super.log(priority, tag, message, t)
            Log.DEBUG -> super.log(priority, tag, message, t)
            Log.INFO -> super.log(priority, tag, message, t)
            Log.WARN -> super.log(priority, tag, message, t)
            Log.ERROR -> super.log(priority, tag, message, t)
            Log.ASSERT -> super.log(priority, tag, message, t)
        }
    }

    override fun createStackElementTag(element: StackTraceElement): String? {
        return "(${element.fileName}:${element.lineNumber})#${element.methodName}"
    }
}

class AppLogger {

    companion object {
        fun init() {
            if (BuildConfig.DEBUG) {
                Timber.plant(Timber.DebugTree())
            } else {
                Timber.plant(LoggingTree())
            }
        }

        fun logUserAuthAttempt(successful: Boolean, userId: String) {
            val message = "User authentication attempt: ${if (successful) "Successful" else "Failed"} for user ID: $userId"
            Timber.i(message)
        }

        fun logDatabaseQuery(query: String, parameters: Map<String, Any>) {
            val paramsString = parameters.entries.joinToString(", ") { "${it.key}=${it.value}" }
            val message = "Database query executed: $query with parameters: $paramsString"
            Timber.v(message)
        }

        fun logApiRequest(url: String, headers: Map<String, String>, body: String) {
            val headersString = headers.entries.joinToString(", ") { "${it.key}=${it.value}" }
            val message = "API request to $url with headers: $headersString and body: $body"
            Timber.v(message)
        }

        fun logException(throwable: Throwable) {
            Timber.e(throwable, "Exception occurred")
        }
    }
}